const postgres = require\('postgres'\);
const sql = postgres\(process.env.DATABASE_URL\);

async function main\(\) {
  // What does spot=true look like? Sample with different rack counts
  const spotTrueWithRacks = await sql\\`SELECT uid, name, bikes, bike_racks, spot FROM places WHERE spot=true AND bike_racks > 0 LIMIT 3\\`;
  const spotTrueNoRacks = await sql\\`SELECT uid, name, bikes, bike_racks, spot FROM places WHERE spot=true AND bike_racks = 0 LIMIT 5\\`;
  const spotFalse = await sql\\`SELECT uid, name, bikes, bike_racks, spot FROM places WHERE spot=false LIMIT 5\\`;

  console.log\('spot=true WITH racks \(real stations\):', JSON.stringify\(spotTrueWithRacks, null, 2\)\);
  console.log\('spot=true NO racks:', JSON.stringify\(spotTrueNoRacks, null, 2\)\);
  console.log\('spot=false:', JSON.stringify\(spotFalse, null, 2\)\);

  // Count breakdown
  const counts = await sql\\`
    SELECT spot, bike_racks > 0 as has_racks, COUNT\(*\) as n
    FROM places GROUP BY spot, has_racks ORDER BY spot, has_racks
  \\`;
  console.log\('Counts by spot + has_racks:', JSON.stringify\(counts, null, 2\)\);

  await sql.end\(\);
}
main\(\).catch\(console.error\);
